import { forEach, map, some } from 'lodash';
import { SystemError } from '../../../error-handling/errors/SystemError';
import { AccordionItem } from './AccordionItem';
import { Container, ContainerProps } from './Container';

export interface AccordionGroupProps extends ContainerProps {
  allowMultipleOpen?: boolean;
  openIndex?: number;
}

export class AccordionGroup extends Container {
  declare protected _children?: AccordionItem[];
  public allowMultipleOpen: boolean;

  constructor(children: AccordionItem[], props?: AccordionGroupProps) {
    super('', props);

    if (!Array.isArray(children) || some(children, (item) => !(item instanceof AccordionItem)))
      throw new SystemError(
        'Invalid children',
        'AccordionGroup  expects an array of AccordionItems'
      );

    this._children = map(children, (item, index) => {
      item.onOpenCallback = () => this._closeAllOtherItems(index);

      return item;
    });

    this.allowMultipleOpen = props?.allowMultipleOpen ?? false;
  }

  protected _closeAllOtherItems(index: number): void {
    if (this.allowMultipleOpen) return;

    forEach(this._children, (item, i) => {
      if (i !== index) {
        item.close();
      }
    });
  }

  protected _applyEventListeners(): void {
    super._applyEventListeners();
  }
}
