import { SystemError } from '../../error-handling/errors/SystemError';
import { ListQueryReturnType } from '../../types/sharepoint/api.types';
import { CurrentUser } from '../user/CurrentUser.abstract';
import { httpDELETERequest, httpPOSTRequest } from './httpRequests';
import { SiteApi } from './SiteApi.class';

/**
 * An object to lookup list items based on CAML query.
 * At the moment only exact values are supported for lookups
 */
export type CAMLQueryObject = Record<string, string>;

export interface ListApiOptions {
  listItemType?: string;
  siteApi?: SiteApi;
}

export class ListApi {
  #title: string;
  #listItemType: string;
  protected _siteApi: SiteApi;

  constructor(title: string, options: ListApiOptions = {}) {
    this._siteApi = options?.siteApi ?? new SiteApi();
    this.#title = title;
    this.#listItemType =
      options.listItemType ??
      `SP.Data.${title.charAt(0).toUpperCase()}${title.substring(1)}ListItem`;
  }

  //============================================================
  protected _parseCAMLQueryObject(args: CAMLQueryObject): string {
    const fieldQueries = Object.entries(args).map(([fieldName, value]) => {
      return `
      <Eq>
        <FieldRef Name="${fieldName}" />
        <Value Type="Text">${value}</Value>
      </Eq>`;
    });

    if (fieldQueries.length === 0) {
      return '<View><Query></Query></View>';
    }

    if (fieldQueries.length === 1) {
      return `<View><Query><Where>${fieldQueries[0]}</Where></Query></View>`;
    }

    let whereClause = fieldQueries[0];
    for (let i = 1; i < fieldQueries.length; i++) {
      whereClause = `
    <And>${whereClause}${fieldQueries[i]}
    </And>`;
    }

    return `<View><Query><Where>${whereClause}</Where></Query></View>`;
  }

  protected _createCAMLQueryPayload(camlQuery: string) {
    const queryPayload = {
      query: {
        // eslint-disable-next-line @typescript-eslint/naming-convention
        __metadata: { type: 'SP.CamlQuery' },
        // eslint-disable-next-line @typescript-eslint/naming-convention
        ViewXml: camlQuery,
      },
    };
    return queryPayload;
  }

  protected _queryRequest<T>(args: CAMLQueryObject | string) {
    let camlQuery = typeof args === 'string' ? args : this._parseCAMLQueryObject(args);
    const payload = this._createCAMLQueryPayload(camlQuery);
    const data = httpPOSTRequest(`${this.endpoint}/getitems`, {
      requestDigest: this._siteApi.requestDigest,
      data: payload,
    }) as ListQueryReturnType<T>;
    return data?.d?.results;
  }
  //============================================================

  //TODO use AI to add the generic type on all get methods

  getItems<T>(query: CAMLQueryObject | string = {}) {
    return this._queryRequest<T>(query);
  }
  getItemByTitle<T>(title: string) {
    // eslint-disable-next-line @typescript-eslint/naming-convention
    return this._queryRequest<T>({ Title: title });
  }
  getItemByUUID<T>(uuid: string) {
    // eslint-disable-next-line @typescript-eslint/naming-convention
    return this._queryRequest<T>({ UUID: uuid });
  }
  getOwnedItems<T>(userId = new CurrentUser().UID) {
    // eslint-disable-next-line @typescript-eslint/naming-convention
    return this._queryRequest<T>({ AuthorId: userId });
  }
  //============================================================
  createItem(item: Record<string, string>) {
    const itemWithMetadata = $.extend(
      {
        // eslint-disable-next-line @typescript-eslint/naming-convention
        __metadata: { type: this.#listItemType },
      },
      item
    );
    const endpoint = `${this.endpoint}/items`;
    return httpPOSTRequest(endpoint, {
      data: itemWithMetadata,
      requestDigest: this._siteApi.requestDigest,
    });
  }
  deleteItem(id: number) {
    const endpoint = `${this.endpoint}/items(${id})`;
    return httpDELETERequest(endpoint, {
      requestDigest: this._siteApi.requestDigest,
    });
  }
  deleteALLItems() {
    // eslint-disable-next-line
    const idList = this.getItems<{ Id: number }>().map((item) => item.Id);

    for (const id of idList) {
      this.deleteItem(id);
    }
  }

  updateItem(_title: string) {
    throw new SystemError('Not implemented', 'Feature not implemented yet');
  }
  //   ===
  get endpoint() {
    return `${this._siteApi.url}/_api/web/lists/getbytitle('${this.#title}')`;
  }
  get listItemType() {
    return this.#listItemType;
  }
}
