import { HTMDNode } from '../types/DOM/HTMDNode.type';
import { StyleResource } from '../DOM/misc/StyleResource';
import { View, ViewProps } from '../DOM/components/container/View';

export interface RouteOptions extends Omit<ViewProps, 'containerSelector'> {
  routeStylePath?: string;
  children?: HTMDNode;
  title?: string;
}

export class Route extends View {
  public title: string;
  protected _routeStyle?: StyleResource;

  constructor(props: RouteOptions = {}) {
    super(props?.children ?? [], props);
    this.title =
      props.title ?? _spPageContextInfo?.webTitle ?? $(`head title`)[0].textContent ?? 'undefined';
    this._routeStyle = props?.routeStylePath ? new StyleResource(props.routeStylePath) : undefined;
  }

  hide(duration?: number, onCompleteCallback?: () => void): void {
    super.hide(duration, () => {
      this._routeStyle?.disable();
      if (onCompleteCallback) onCompleteCallback();
    });
  }
  async show(duration?: number, onCompleteCallback?: () => void) {
    this._routeStyle?.enable();
    super.show(duration, () => {
      if (onCompleteCallback) onCompleteCallback();
    });
  }

  set routeStylePath(path: string) {
    if (this._routeStyle) this._routeStyle.remove();
    this._routeStyle = new StyleResource(path);
  }

  set onRefreshHandler(callback: () => void) {
    this._onRefresh = callback;
  }
}
