import { each, orderBy, reduce } from 'lodash';
import { HTMDElement, HTMDElementProps } from '../../abstracts/HTMDElement.abstract';
import { getIcon } from '../media/Icon';

export interface ListProps<T extends string | number> extends HTMDElementProps {
  headers: string[];
  data: T[][];
  emptyListMessage?: string;
  onItemSelectHandler?: (rowData: T[]) => void;
}

export class List<T extends string | number> extends HTMDElement {
  public headers: string[];
  protected _data: T[][];
  private _orderedData: T[][];
  public emptyListMessage: string;
  onItemSelectHandler: (rowData: T[]) => void;

  constructor(props: ListProps<T>) {
    super(undefined, props);

    this.headers = props.headers || [];
    this._data = props.data || [];
    this._orderedData = this._data;
    this.throwOnInvalidListData();
    this.emptyListMessage = props?.emptyListMessage || 'No items to display';
    this.onItemSelectHandler = props?.onItemSelectHandler || (() => {});
  }

  private _createHeaders(data: T[] | string[]) {
    return `<tr class="${this.topClassBEM}__header ${this.topClassBEM}__row">${reduce(
      data,
      (acc, item) =>
        (acc += `<th class="${this.topClassBEM}__col " title="${item}">
        <span class="${this.topClassBEM}__header__text">${item}</span>
        <div class="${this.topClassBEM}__header__order-icons">
          <span class="${this.topClassBEM}__header__ascending-icon">${getIcon('sort-asc')}</span>
          <span class="${this.topClassBEM}__header__descending-icon">${getIcon('sort-desc')}</span>
        </div>
        </th>`),
      ''
    )}</tr>`;
  }
  private _createRow(data: T[] | string[], emptyRow?: boolean) {
    return `<tr 
              class="${this.topClassBEM}__row ${emptyRow ? `${this.topClassBEM}__row--empty` : ''}"
            >${reduce(
              data,
              (acc, item) =>
                (acc += `<td class="${this.topClassBEM}__col" title="${item}" ${emptyRow ? `colspan=${this.headers.length}` : ''}>${item}</td>`),
              ''
            )}</tr>`;
  }

  private _createListItems(list: T[][] = this._data) {
    return list.length === 0
      ? this._createRow([this.emptyListMessage], true)
      : reduce(list, (acc, item) => (acc += this._createRow(item)), '');
  }

  toString() {
    return `<div id="${this.id}" class="${this.class}">
                <table 
                    class="${this.topClassBEM}__table"
                    tabindex='-1'
                >
                          <thead>${this._createHeaders(this.headers)}</thead>
                          <tbody>${this._createListItems(this._orderedData)}</tbody>
                </table>
            </div>
                `;
  }
  private _refreshDataset(data: T[][]) {
    this.instance?.find('tbody').html(this._createListItems(data));
    this._applyDatasetEventListeners();
  }

  //=============================== EVENT HANDLERS START
  private _defaultOrderingFn(headerIndex: number, order?: 'asc' | 'desc') {
    if (order) {
      return orderBy(this._data, (item) => item[headerIndex], order);
    } else return this._data;
  }
  private _applySortClass(element: JQuery<HTMLElement>, index: number) {
    const ascendingClass = `${this.topClassBEM}__header--ascending`,
      descendingClass = `${this.topClassBEM}__header--descending`;

    //should improve this cz im already looping these elements on _onHeaderSortEventListeners()
    const headers = this.instance?.find(
      `.${this.topClassBEM}__header .${this.topClassBEM}__col`
    ) as JQuery<HTMLElement>;
    //only one sorted at a time
    each(headers, (h, i) => {
      if (i !== index) $(h).removeClass([ascendingClass, descendingClass]);
    });

    if (element.hasClass(ascendingClass)) {
      element.removeClass(ascendingClass);
      element.addClass(descendingClass);
      return 'desc';
    } else if (element.hasClass(descendingClass)) {
      element.removeClass(descendingClass);
      return undefined;
    } else {
      element.addClass(ascendingClass);
      return 'asc';
    }
  }
  private _handleHeaderSortEvent(element: JQuery<HTMLElement>, index: number) {
    element.on('click', () => {
      const order = this._applySortClass(element, index);
      this._orderedData = this._defaultOrderingFn(index, order);
      this._refreshDataset(this._orderedData);
    });
  }

  private _onHeaderSortEventListeners() {
    const headers = this.instance?.find(
      `.${this.topClassBEM}__header .${this.topClassBEM}__col`
    ) as JQuery<HTMLElement>;
    each(headers, (h, i) => this._handleHeaderSortEvent($(h), i));
  }

  private _onItemSelectEventListeners() {
    if (!this?.onItemSelectHandler || this.data.length === 0) {
      return;
    }
    const elements = this.instance?.find(`tbody .${this.topClassBEM}__row`) as JQuery<HTMLElement>;

    each(elements, (el, index) => {
      $(el).on('click', () => {
        this.onItemSelectHandler(this._orderedData[index]);
      });
    });
  }
  private _applyDatasetEventListeners() {
    this._onItemSelectEventListeners();
  }
  protected _applyEventListeners(): void {
    super._applyEventListeners();
    this._onHeaderSortEventListeners();
    this._applyDatasetEventListeners();
  }
  //=============================== EVENT HANDLERS END

  set data(data: T[][]) {
    this._data = data;
    this._orderedData = data;
    this.throwOnInvalidListData();
    this._refreshDataset(data);
  }
  get data() {
    return this._data;
  }

  get isDataValid() {
    if (this._data.length === 0) return true;
    return this._data[0]?.length === this.headers.length;
  }
  throwOnInvalidListData() {
    if (!this.isDataValid)
      throw new Error("List headers don't match the number of item properties");
  }
}
