import 'jquery-ui/ui/widgets/datepicker';
import { FormField } from '../../../../utils/form/FormField.class';
import { FormControl } from '../../../abstracts/FormControl.abstract';
/*
📋 Full List of datepicker Options
📅 Display and Behavior
Option	Type	Description
altField	string	Selector for an alternate input to store the formatted date
altFormat	string	Format for the altField (default: same as dateFormat)
appendText	string	Text to display after the input field
autoSize	boolean	Auto-resize input to fit the date
buttonImage	string	Path to image to use for the calendar icon
buttonImageOnly	boolean	Show only the image, not the button
buttonText	string	Text for the trigger button
changeMonth	boolean	Show a month dropdown
changeYear	boolean	Show a year dropdown
closeText	string	Text for the "Close" button
constrainInput	boolean	Prevent invalid characters
currentText	string	Label for "Today" link
dateFormat	string	Format for the displayed date (yy-mm-dd, dd/mm/yy, etc.)
dayNames	string[]	Full names for days (['Sunday', ..., 'Saturday'])
dayNamesMin	string[]	Minimized day names (['Su', 'Mo', ..., 'Sa'])
dayNamesShort	string[]	Shortened day names
defaultDate	`string	Date
duration	string	Animation speed ('fast', 'slow', or time in ms)
firstDay	number	Day of week to start on (0 = Sunday, 1 = Monday, etc.)
gotoCurrent	boolean	If true, go to current selected date on open
hideIfNoPrevNext	boolean	Hide next/prev buttons if not valid
isRTL	boolean	Right-to-left layout
maxDate	`Date	string
minDate	`Date	string
monthNames	string[]	Full month names
monthNamesShort	string[]	Short month names
navigationAsDateFormat	boolean	Format prev/next buttons as dates
nextText	string	Text for next month button
numberOfMonths	`number	[number, number]`
prevText	string	Text for previous month button
selectOtherMonths	boolean	Allow selection of days from other months
shortYearCutoff	`string	number`
showAnim	string	Animation name ('fadeIn', 'slideDown', 'fold', etc.)
showButtonPanel	boolean	Show "Today" and "Done" buttons
showCurrentAtPos	number	Month to show initially (0 = current)
showMonthAfterYear	boolean	Display month dropdown after year
showOn	string	Trigger: 'focus', 'button', 'both'
showOptions	object	Additional options for animations
showOtherMonths	boolean	Show days from other months in calendar
stepMonths	number	Number of months to jump with prev/next
weekHeader	string	Label for the week column
yearRange	string	e.g. '2000:2025', '-10:+10'
yearSuffix	string	Text to append to the year dropdown

⚡ Event Callbacks
Callback	Signature
beforeShow	(input: HTMLElement, inst: object) => void
beforeShowDay	(date: Date) => [boolean, string, string?] – allows disabling or styling specific days
onChangeMonthYear	(year: number, month: number, inst: object) => void
onClose	(dateText: string, inst: object) => void
onSelect	(dateText: string, inst: object) => void

🛠️ Common Methods (called like .datepicker('method'))
Method	Usage
destroy	Remove the widget
getDate	Returns selected Date object
hide	Hide the datepicker
refresh	Redraw the UI
setDate	.datepicker('setDate', new Date())
show	Show the picker
option	Get/set options dynamically
 */
export type DATE_FORMATS = 'dd-mm-yyyy' | 'mm-dd-yyyy';

export interface DateInputProps extends FormControl<string> {
  format?: DATE_FORMATS;
}

export class DateInput extends FormControl<string> {
  public format: DATE_FORMATS;
  constructor(fieldOrValue: string | FormField<string>, props: DateInputProps) {
    super(fieldOrValue, props);
    this.format = props?.format ?? 'dd-mm-yyyy';
  }

  toString(): string {
    return `<input 
                    title="${this.value}"
                    id="${this.id}"
                    class="${this.class} ${super.modifierClasses} "
                    type="text"
                    autocomplete="off"
                    tabindex=0
                    ${this.isDisabled ? 'disabled' : ''}
                    value="${this._value.value}"
                    />`;
  }

  protected _applyEventListeners(): void {
    super._applyEventListeners();

    this.setEventHandler('change', () => {
      this._value.value = this.instance?.val() as string;
      if (this._value.wasTouched) {
        this._validate();
      }
    });
  }

  private _getDatepickerFormat(): string {
    const formatMap: Record<DATE_FORMATS, string> = {
      'dd-mm-yyyy': 'dd-mm-yy',
      'mm-dd-yyyy': 'mm-dd-yy',
    };
    return formatMap[this.format] || 'dd-mm-yy';
  }

  render() {
    super.render();

    setTimeout(() => {
      (
        this.instance as unknown as {
          datepicker: (options: { dateFormat: string }) => void;
        }
      ).datepicker({ dateFormat: this._getDatepickerFormat() });
    }, 0);
  }
}
