import { FormField, FormFieldType } from '../../utils/form/FormField.class';
import { HTMDElement, HTMDElementProps } from './HTMDElement.abstract';

export interface FormControlProps extends HTMDElementProps {
  /**
   * Use this boolean flag to toggle a css class disabling interactions with the component.
   */
  isDisabled?: boolean;
  /**
   * Use this boolean flag to toggle a css class while the async component loads.
   */
  isLoading?: boolean;
  /**
   * Currently used as a tooltip. Displays the current value by default
   */
  title?: string;
}

export abstract class FormControl<T extends FormFieldType> extends HTMDElement {
  protected _value: FormField<T>;
  protected _isDisabled: boolean;
  protected _isLoading: boolean;
  public title: string;

  constructor(fieldOrValue: T | FormField<T>, props: FormControlProps = {}) {
    super(undefined, props);
    if (fieldOrValue instanceof FormField) {
      this._value = fieldOrValue;
      this._value.inputSelector = this.selector;
    } else {
      this._value = new FormField<T>({ value: fieldOrValue });
    }
    //
    this._isDisabled = props?.isDisabled || false;
    this._isLoading = props?.isLoading || false;

    this.title = props?.title || '';
  }

  //=======================================================================================

  //=================================================== VALIDATION
  private get _validationClass() {
    if (this._value.hasValidation && this._value.wasTouched)
      return this._value.isValid ? 'form-control--valid' : 'form-control--invalid';
    else return '';
  }
  protected _validate() {
    if (!this.instance) return;

    this.instance.removeClass(this._validationClass);
    this.class = this.class.replace(this._validationClass, '');

    this._value.validate();

    this.instance.addClass(this._validationClass);
    this.class += this._validationClass;
  }
  //=======================================================================================
  //=================================================== UTILS

  toggleDisabledState() {
    this._isDisabled = !this._isDisabled;
    this.render();
  }
  toggleLoadingState() {
    this._isLoading = !this._isLoading;
    this.render();
  }

  get modifierClasses() {
    let mods: string[] = [];
    const prefix = 'form-control--';

    if (this._isDisabled) mods.push(prefix + 'disabled');
    if (this._isLoading) mods.push(prefix + 'loading');

    return mods.join(' ');
  }

  //=================================================== GETTERS & SETTERS
  set class(str) {
    super.class = `form-control${str ? ` ${str}` : ''}`;
  }
  get class() {
    return super.class;
  }
  get isValid() {
    return this._value.isValid;
  }
  get wasTouched() {
    return this._value.wasTouched;
  }
  get value() {
    return this._value;
  }
  set isDisabled(flag: boolean) {
    this._isDisabled = flag;
    this.render();
  }
  get isDisabled() {
    return this._isDisabled;
  }
  set isLoading(flag: boolean) {
    this._isLoading = flag;
    this.render();
  }
  get isLoading() {
    return this._isLoading;
  }

  //===================================================
}
