import { FormField } from '../../../../utils/form/FormField.class';
import { FormControl, FormControlProps } from '../../../abstracts/FormControl.abstract';
import { getIcon } from '../../media/Icon';

export class CheckBox extends FormControl<boolean> {
  constructor(fieldOrValue: boolean | FormField<boolean>, props: FormControlProps) {
    super(fieldOrValue, props);
  }

  protected _applyEventListeners(): void {
    super._applyEventListeners();

    this.setEventHandler('click', (e) => {
      if (!(e.target instanceof HTMLInputElement)) return;
      this._value.value = this.instance?.find('input')[0].checked ?? false;
    });
  }

  toString() {
    return `<label 
                 id="${this.id}"
                 class="${this.class} ${super.modifierClasses} " 
                 tabindex=0
             >
                 <input type="checkbox" ${this._value.value ? 'checked' : ''}/>
                 ${getIcon('check-line')}
             </label>`;
  }
}
