import { cloneDeep } from 'lodash';
import { ComboBoxOptionProps } from '../../DOM/components/form/combobox/ComboBox';

export type FormFieldType = string | number | boolean | ComboBoxOptionProps | ComboBoxOptionProps[];

export interface FormFieldProps<T extends FormFieldType> {
  value: T;
  validatorCallback?: (v: T) => boolean;
  onChangeHandler?: (v: T) => void;
}

export class FormField<T extends FormFieldType> {
  private _value: T;
  private _inputSelector?: string;
  private _validatorCallback?: (v: T) => boolean;
  private _onChangeHandler?: (v: T) => void;
  //
  private _isValid: boolean;
  private _wasTouched: boolean;

  constructor(props?: FormFieldProps<T>) {
    this._value = props?.value ? cloneDeep(props?.value) : ('' as T);
    this._isValid = false;
    this._wasTouched = false;

    this._validatorCallback = props?.validatorCallback;
    this._onChangeHandler = props?.onChangeHandler;
  }

  //=========================================

  [Symbol.toStringTag]() {
    return 'Form Field';
  }

  [Symbol.toPrimitive]() {
    return this.toString();
  }

  toString() {
    if (typeof this._value === 'object' && 'label' in this._value) {
      //its either a ComboBoxOption, or array of options
      if (Array.isArray(this._value)) return this._value.map((e) => e.label).join(', ');
      else return this._value.label;
    } else return this._value;
  }
  //=========================================
  validate() {
    if (typeof this?._validatorCallback !== 'function') return null;

    this._isValid = this._validatorCallback(this._value);

    return this._isValid;
  }
  //=========================================

  focusOnInput() {
    if (!this._inputSelector) return; //IMPROVE: should throw proper error here - see issue #12
    $(this._inputSelector).trigger('focus');
  }

  //=========================================

  set value(data: T) {
    this._value = cloneDeep(data);
    this._wasTouched = true;
    if (this._onChangeHandler) this._onChangeHandler(this._value);
  }

  set inputSelector(selector: string) {
    if (this._validatorCallback) this._inputSelector = selector;
  }

  get value() {
    return this._value;
  }

  get wasTouched() {
    return this._wasTouched;
  }

  get isValid() {
    return this._isValid;
  }

  get hasValidation() {
    return typeof this._validatorCallback === 'function';
  }
}
