import { ErrorBoundary } from '../error-handling/ErrorBoundary';
import { SystemError } from '../error-handling/errors/SystemError';
import { NavigationEvent } from '../events/navigation/NavigationEvent.event';
import { resolvePath } from '../utils/misc/path';
import { Route } from './Route';

export interface NavigationOptions {
  query?: Record<string, string>;
  newTab?: boolean;
}

/**
 * @property {string} containerSelector A css selector defining where the router wrapper should be placed. Defaults to `#root`
 * @property {unknown} initialState initializes data that is available to all routes from the start
 */
export interface RouterProps {
  containerSelector?: string;
  enableErrorBoundary: boolean;
}

export type RoutePaths = string[];

export class Router {
  //@ts-expect-error Property has initializer, but ts complains due to singleton pattern
  #containerSelector: string;
  //@ts-expect-error Property has initializer, but ts complains due to singleton pattern
  #routesMap: Map<string, Route>;
  //@ts-expect-error Property has initializer, but ts complains due to singleton pattern
  #routePaths: RoutePaths;

  #errorBoundary?: ErrorBoundary;

  //======================================
  protected static _runtimeInstance: Router;

  public static navigateTo(path: string, options?: NavigationOptions) {
    Router.#checkSingletonInstance();

    Router._runtimeInstance._navigateTo(path, options);
  }
  public static goBack() {
    history.back();
  }

  public static popLevel(x = 1) {
    Router.#checkSingletonInstance();
    Router._runtimeInstance._popLevel(x);
  }

  static get location() {
    return location.hash.replace(/^#\//, '') || '/';
  }
  static get absoluteURI() {
    return location.href;
  }
  static get siteRootPath() {
    return _spPageContextInfo.webAbsoluteUrl;
  }

  static get pageRootPath() {
    return Router.absoluteURI.split(/[#?]/)[0];
  }

  static get queryParams() {
    return new URLSearchParams(window.location.search);
  }

  static #checkSingletonInstance() {
    if (!Router._runtimeInstance)
      throw new SystemError(
        `InternalError`,
        `Router is not initialized. Router follows the singleton pattern. Please initialize the router with valid routes at the top of your application`
      );
  }

  //======================================

  constructor(routeRelativePaths: RoutePaths, props?: RouterProps) {
    if (!Router._runtimeInstance && routeRelativePaths) {
      this.#containerSelector = props?.containerSelector ?? '#root';

      this.#errorBoundary =
        props?.enableErrorBoundary === false ? undefined : new ErrorBoundary({ name: `router ` });

      this.#routesMap = new Map();

      this.#routePaths = ['/', ...routeRelativePaths];

      Router._runtimeInstance = this;
      this._refreshCurrentPage();
      this._addPopStateEventListeners();
    }

    return Router._runtimeInstance;
  }

  [Symbol.toStringTag]() {
    return 'Router';
  }

  private _resolveRouteAbsolutePath(path: string) {
    const localPath = path === '/' ? '' : path + '/';
    return resolvePath(`@/routes/${localPath}route.js`);
  }

  private _addPopStateEventListeners() {
    window.addEventListener('popstate', () => {
      this._refreshCurrentPage();
    });
  }

  private _cleanup() {
    $(this.#containerSelector)?.find('*').addBack().off();
    $(this.#containerSelector).html(``);
  }

  private async _refreshCurrentPage() {
    this._cleanup();

    const queryParams = Router.queryParams;
    const queryObject = Object.fromEntries(queryParams.entries()) as Record<string, string>;

    this._navigateTo(Router.location, { query: queryObject });
  }

  private _addImportedRoute(path: string, route: Route) {
    route.containerSelector = this.#containerSelector;
    route.class = `${path.replace('/', '-')}-route`;
    route.routeStylePath = resolvePath(`@/routes/${path}/route.css`);
    this.#routesMap.set(path, route);
  }
  private async _loadRoute(path: string) {
    if (this.#routesMap.has(path)) return this.#routesMap.get(path);
    //
    else if (this.#routePaths.includes(path)) {
      let resolvedRouteFilePath = '';
      try {
        resolvedRouteFilePath = this._resolveRouteAbsolutePath(path);
        const module = await import(resolvedRouteFilePath);

        const route = await module?.default;

        if (route && route instanceof Route) {
          this._addImportedRoute(path, route);

          return route;
        } else {
          throw new Error(
            `File ${resolvedRouteFilePath} was found, but Route needs to be exported as default.`
          );
        }
      } catch (error) {
        console.error(
          `Failed to load the route: ${path}, from the file ${resolvedRouteFilePath}`,
          error
        );
        throw error;
      }
    } else {
      throw new Error(`Path: ${path} is not defined on current Router object.`);
    }
  }
  private _parseQueryParamsToString(obj: Record<string, string> = {}): string {
    let queryString = '?';
    for (const [key, value] of Object.entries(obj)) {
      queryString += `${key}=${value}&`;
    }
    return queryString;
  }
  #createUrls(path: string, options?: NavigationOptions) {
    const basePath = options?.newTab ? Router.pageRootPath : '';
    const queryParams = this._parseQueryParamsToString(options?.query);

    // Handle relative paths (./path)
    let routePath = /^\.\//.test(path)
      ? `${Router.location === '/' ? '' : Router.location + '/'}${path.substring(2)}`
      : path;

    // Normalize: strip leading slash UNLESS it's the home route "/"
    if (routePath !== '/' && routePath.startsWith('/')) {
      routePath = routePath.substring(1);
    }

    const hashPath = `#/${routePath === '/' ? '' : routePath}`;

    return [basePath + queryParams + hashPath, routePath];
  }
  private async _navigateTo(path: string, options?: NavigationOptions) {
    const [browserUrl, internalUrl] = this.#createUrls(path, options);
    ///===================== external navigation
    if (options?.newTab) {
      window.open(browserUrl, '_blank');
      return;
    }
    //===================== internal navigation
    const fromPath = Router.location;
    //update url so that routes can use queryParams
    history.pushState(null, '', browserUrl);

    //load route
    const newRoute = (await this._loadRoute(internalUrl)) as Route,
      oldRoute = this.#routesMap.get(fromPath);

    if (oldRoute?.isAlive) oldRoute.hide(300, () => this._applyRoute(newRoute));
    else this._applyRoute(newRoute);

    new NavigationEvent(internalUrl, fromPath, options?.query).dispatch();
  }

  protected _applyRoute(route: Route) {
    try {
      document.title = route.title;
      route.render(); //always refresh page! Future functionality could include persisting state between routes
    } catch (error) {
      throw new SystemError(
        `RouteError`,
        `Error loading route on ${Router.location}. \n Error: ${(error as Error).message} `
      );
    }
  }

  /**
   * Goes up x levels on the current URL.
   * Different from router.goBack()
   * @default 1
   * @example
   * router.location // .../sites/MySite/somePage/subpage/etc
   * router.popLevel() // navigates to .../sites/MySite/somePage/subpage/
   * router.popLevel(2) // navigates to .../sites/MySite/
   */
  private _popLevel(x = 1) {
    const path = Router.location.split('/');

    if (path.length <= 1) this._navigateTo('/');
    this._navigateTo(path.slice(0, path.length - x).join('/'));
  }
}
