import { SystemError } from '../../error-handling/errors/SystemError';
import { isCallable } from '../../utils/misc/type-safety';

export interface CurrentUserOptions {
  bruteForceAccountNameClientImplementation?: (_str: string, _tryCount: number) => string;
  userUIDParserClientImplementation?: (_str: string) => string;
}

export class CurrentUser {
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _UID: string;
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _AccountName: string;
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _Country: string;
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _City: string;
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _DisplayName: string;
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _Email: string;
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _Manager: string;
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _Peers: string[];
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _SPGroupId: number;
  //@ts-expect-error property is defined on getUserData
  // eslint-disable-next-line @typescript-eslint/naming-convention
  protected _SPGroupTitle: string;

  /** Singleton Pattern */
  static #runtimeInstance: CurrentUser;

  protected _bruteForceAccountNameClientImplementation: CurrentUserOptions['bruteForceAccountNameClientImplementation'];

  protected _userUIDParserClientImplementation: CurrentUserOptions['userUIDParserClientImplementation'];

  constructor(accountName = _spPageContextInfo.userLoginName, options: CurrentUserOptions = {}) {
    if (CurrentUser.#runtimeInstance) return CurrentUser.#runtimeInstance;

    if (
      !isCallable(options.bruteForceAccountNameClientImplementation) ||
      !isCallable(options.userUIDParserClientImplementation)
    )
      throw new SystemError('MissingConcreteImplementation', 'At CurrentUser definition');

    this._bruteForceAccountNameClientImplementation =
      options.bruteForceAccountNameClientImplementation;
    this._userUIDParserClientImplementation = options.userUIDParserClientImplementation;

    this._UID = this._userUIDParserClientImplementation(accountName);
    this._loadUserData();

    CurrentUser.#runtimeInstance = this;
  }
  /**
   * This should only be defined in the client environment, due to security compliance
   */
  protected _bruteForceAccountName(_str: string, _tryCount: number): string {
    return this._bruteForceAccountNameClientImplementation?.(_str, _tryCount) as string;
  }
  /**
   * This should only be defined in the client environment, due to security compliance
   */
  protected _userUIDParser(_str: string): string {
    return this._userUIDParserClientImplementation?.(_str) as string;
  }

  //========================================== GETTERS

  protected _loadUserData() {
    let bruteForceCounter = 0;
    let infiniteLoopLoopProtection = 0;
    do {
      let accountName = this._bruteForceAccountName(this._UID, bruteForceCounter);

      if (!accountName) {
        throw new Error(`Impossible to retrieve user with id ${this._UID}`);
      }

      this._getUserData(accountName);
      infiniteLoopLoopProtection++;
    } while (!this.isUserDefined && infiniteLoopLoopProtection < 100);
  }

  protected _getUserData(accountName: string) {
    // eslint-disable-next-line @typescript-eslint/no-this-alias
    const classThis = this;

    const apiUrl = `${_spPageContextInfo.webAbsoluteUrl}/_api/`;
    const url = `${apiUrl}/SP.UserProfiles.PeopleManager/GetPropertiesFor(accountName=@v)?@v='${accountName}'`;
    $.ajax({
      async: false,
      url,
      method: 'GET',
      headers: { accept: 'application/json; odata=verbose' },
      success: (res) => {
        if (typeof res?.d === 'object' && res.d.hasOwnProperty('GetPropertiesFor')) {
          return; // user not found
        }

        const user = res.d;

        const url = `${apiUrl}/Web/siteusers/getbyemail('${user.Email}')/Groups`;
        $.ajax({
          async: false,
          url,
          method: 'GET',
          headers: {
            // eslint-disable-next-line @typescript-eslint/naming-convention
            'X-RequestDigest': `${$('#__REQUESTDIGEST').val()}`,
            accept: 'application/json; odata=verbose',
          },
          success: (res) => {
            if (!res.d.results?.length || res.d.results?.length === 0) {
              throw new Error('User found, but unable to retrieve group information');
            }

            const { Id, Title } = res.d.results[0];
            classThis._AccountName = user.AccountName;
            classThis._City = user.City;
            classThis._Country = user.Country;
            classThis._DisplayName = user.DisplayName;
            classThis._Email = user.Email;
            classThis._Manager = user.Manager;
            classThis._Peers = user.Peers;
            classThis._SPGroupId = Id;
            classThis._SPGroupTitle = Title;
          },
        });
      },
    });
  }

  //========================================== GETTERS
  get isUserDefined() {
    return this?.DisplayName ? true : false;
  }
  /**
   * Gets the city associated with the current user.
   * @returns The city name as a string.
   */
  // eslint-disable-next-line @typescript-eslint/naming-convention
  get City() {
    return this._City;
  }
  /**
   * Gets the account name of the current user.
   * @returns The account name as a string.
   */
  // eslint-disable-next-line @typescript-eslint/naming-convention
  get AccountName() {
    return this._AccountName;
  }
  /**
   * Gets the country associated with the current user.
   * @returns The country name as a string.
   */
  // eslint-disable-next-line @typescript-eslint/naming-convention
  get Country() {
    return this._Country;
  }
  /**
   * Gets the display name of the current user.
   * @returns The display name as a string.
   */
  // eslint-disable-next-line @typescript-eslint/naming-convention
  get DisplayName() {
    return this._DisplayName;
  }
  /**
   * Gets the UID of the current user.
   * @returns The UID as a string.
   */
  // eslint-disable-next-line @typescript-eslint/naming-convention
  get UID() {
    return this._userUIDParser(this.AccountName);
  }
  /**
   * Gets the email of the current user.
   * @returns The email as a string.
   */
  // eslint-disable-next-line @typescript-eslint/naming-convention
  get Email() {
    return this._Email;
  }
  /**
   * Gets the manager of the current user.
   * @returns The manager as a string.
   */
  // eslint-disable-next-line @typescript-eslint/naming-convention
  get Manager() {
    return this._Manager;
  }
  /**
   * Gets the peers of the current user.
   * @returns An array of peer names.
   */
  // eslint-disable-next-line @typescript-eslint/naming-convention
  get Peers() {
    return this._Peers;
  }
  /**
   * Gets the SharePoint group ID of the current user.
   * @returns The group ID as a number.
   */
  get groupId() {
    return this._SPGroupId;
  }
  /**
   * Gets the SharePoint group title of the current user.
   * @returns The group title as a string.
   */
  get groupTitle() {
    return this._SPGroupTitle;
  }
}
