import { RuntimeEvent, RuntimeEventListenerOptions } from '../RuntimeEvent.abstract';

export class NavigationEvent extends RuntimeEvent {
  #from?: string;
  #to: string;
  #query?: Record<string, string>;
  constructor(to: string, from?: string, query?: Record<string, string>) {
    super(window);
    this.#from = from;
    this.#to = to;
    this.#query = query;
  }

  /**
   * IMPORTANT: ADD NOTE ABOUT CALLING THE CLEANUP FN BEFORE CREATING A LISTENER THAT IS CREATED
   * ON EACH RENDER/REFRESH
   *
   */
  static listener(
    callback: (event?: NavigationEvent) => void,
    options?: RuntimeEventListenerOptions
  ) {
    return RuntimeEvent._createListener('navigationevent', callback, window, options);
  }

  get from() {
    return this.#from;
  }
  get to() {
    return this.#to;
  }
  get query() {
    return this.#query;
  }
}
