import { SystemError } from '../../error-handling/errors/SystemError';
import { Router } from '../../routing/Router';

// export interface SiteApiOptions {}

export class SiteApi {
  #url: string;
  #tokenExpiresAt: number;
  #requestDigest: string;

  constructor(absoluteUrl?: string) {
    this.#url = absoluteUrl ?? Router.siteRootPath;
    this.#requestDigest = '';
    this.#tokenExpiresAt = 0;
  }

  //=================================================== Request Digest Token START
  protected _refreshRequestDigest(): [string, number] {
    let token = '',
      expiration = 0;
    if (this.#url === Router.siteRootPath) {
      token = $('#__REQUESTDIGEST').val() as string;
      expiration = 0; // according to SharePoint documentation, token validity on local site is handled by SharePoint itself with an expiration time of 30min. Although due to some internal quirks, and since theres no actual request involved, this value should not be cached
    } else {
      throw new SystemError('Not Implemented', 'Cannot refresh request digest on a remote site');
    }

    this.#requestDigest = token;
    this.#tokenExpiresAt = expiration;
    return [token, expiration];
  }

  protected get _isTokenValid() {
    return new Date().getTime() < this.#tokenExpiresAt;
  }

  get requestDigest() {
    if (this._isTokenValid) return this.#requestDigest;

    return this._refreshRequestDigest()[0];
  }
  //=================================================== Request Digest Token END

  get url(): string {
    return this.#url;
  }
}
