import { SystemError } from '../../error-handling/errors/SystemError';

export interface RequestOptions extends JQueryAjaxSettings {
  /*
    *JQueryAjaxSettings
    $.ajax({
      * URL and Method
      url: string,                    // The URL to request
      type: string,                   // HTTP method: 'GET', 'POST', 'PUT', 'DELETE', etc.
      method: string,                 // Alias for 'type'

      * Data
      data: any,                      // Data to send to server
      dataType: string,              // Expected data type: 'json', 'xml', 'html', 'text', 'script'
      contentType: string | false,   // Content-Type header for request
      processData: boolean,          // Whether to process data into query string

      * Async/Timing
      async: boolean,                // Asynchronous (true) or synchronous (false)
      timeout: number,               // Request timeout in milliseconds

      * Headers and Authentication
      headers: Record<string, string>, // Custom HTTP headers
      username: string,              // Username for HTTP authentication
      password: string,              // Password for HTTP authentication
      xhrFields: any,                // Native XHR object properties (e.g., withCredentials)

      * Callbacks
      success: (data, textStatus, jqXHR) => void,
      error: (jqXHR, textStatus, errorThrown) => void,
      complete: (jqXHR, textStatus) => void,
      beforeSend: (jqXHR, settings) => void | false,

      * Caching
      cache: boolean,                // Whether to cache the request
      ifModified: boolean,           // Only succeed if response has changed

      * JSONP specific
      jsonp: string | false,         // Override callback function name for JSONP
      jsonpCallback: string | (() => string), // Specify callback name for JSONP

      * Other
      context: any,                  // Context for callback functions
      global: boolean,               // Whether to trigger global AJAX events
      statusCode: Record<number, () => void>, // HTTP status code handlers
      accepts: Record<string, string>, // Request headers for dataType
      converters: Record<string, (value: any) => any>, // Data type converters
      crossDomain: boolean,          // Force cross-domain request
      traditional: boolean,          // Use traditional param serialization
      scriptCharset: string,         // Charset for script/jsonp requests
    });
    */
  requestDigest?: string;
}

export function baseRequest<T>(ajaxPayload: JQueryAjaxSettings) {
  try {
    let response: unknown;

    $.ajax(ajaxPayload).then((res) => (response = res));

    return response as T;
  } catch (error) {
    throw new SystemError(`APIException: ${ajaxPayload.type}`, (error as Error).message);
  }
}

export function httpGETRequest(url: string, options: RequestOptions = {}) {
  const { headers, ...requestOptions } = options;
  const requestHeaders = $.extend(
    {
      accept: 'application/json;odata=verbose',
    },
    headers ?? {}
  );

  const ajaxPayload = $.extend(
    {
      url,
      async: false,
      type: 'GET',
      dataType: 'json',
    },
    requestOptions,
    { headers: requestHeaders }
  );

  return baseRequest(ajaxPayload);
}
export function httpPOSTRequest(url: string, options: RequestOptions = {}) {
  const { headers, data, ...requestOptions } = options;
  /* eslint-disable @typescript-eslint/naming-convention */
  const requestHeaders = $.extend(
    {
      accept: 'application/json;odata=verbose',
      'X-HTTP-Method': 'POST',
      'Content-Type': 'application/json;odata=verbose',
    },
    headers ?? {}
  );

  if (options?.requestDigest) requestHeaders['X-RequestDigest'] = options.requestDigest;

  const ajaxPayload = $.extend(
    {
      url,
      async: false,
      type: 'POST',
      data: JSON.stringify(data),
      dataType: 'json',
    },
    requestOptions,
    { headers: requestHeaders }
  );

  return baseRequest(ajaxPayload);
}

export function httpDELETERequest(url: string, options: RequestOptions = {}) {
  const { headers, ...requestOptions } = options;
  /* eslint-disable @typescript-eslint/naming-convention */
  const requestHeaders = $.extend(
    {
      accept: 'application/json;odata=verbose',
      'X-RequestDigest': options?.requestDigest ?? '',
      'X-HTTP-Method': 'DELETE',
      'Content-Type': 'application/json;odata=verbose',
      'IF-MATCH': '*',
    },
    headers ?? {}
  );

  if (options?.requestDigest) requestHeaders['X-RequestDigest'] = options.requestDigest;

  const ajaxPayload = $.extend(
    {
      url,
      async: false,
      type: 'POST',
    },
    requestOptions,
    { headers: requestHeaders }
  );

  return baseRequest(ajaxPayload);
}
