import { HTMDNode } from '../../../../types/DOM/HTMDNode.type';
import { FormControl, FormControlProps } from '../../../abstracts/FormControl.abstract';

export interface ButtonProps extends FormControlProps {
  /** HTML attr. Defaults to "button" */
  type?: 'button' | 'submit' | 'reset';
  /** Defines the element styling variant. @default "primary" */
  variant?: 'primary' | 'secondary' | 'danger';
  /** Applies the outlined styling variant. @default false */
  isOutlined?: boolean;
  /** Sets equal width/height, useful for styling Icon Buttons. @default false */
  squared?: boolean;
  /** */
  onClickHandler: (e: MouseEvent) => void;
}

export class Button extends FormControl<string> {
  public type: ButtonProps['type'];
  public variant: ButtonProps['variant'];
  public isOutlined: boolean;
  public isSquared: boolean;

  constructor(children: HTMDNode, props: ButtonProps) {
    super('button', props);
    this._children = children;
    this.type = props?.type || 'button';
    this.variant = props?.variant || 'primary';
    this.isOutlined = props?.isOutlined || false;
    this.isSquared = props?.squared || false;
    this.onClickHandler = props.onClickHandler;
  }

  get modifierClasses() {
    const mods: string[] = [];
    mods.push(`${this.topClassBEM}--${this.variant}`);
    if (this.isOutlined) mods.push(`form-controls--outlined`);
    if (this.isSquared) mods.push(`${this.topClassBEM}--squared`);
    return `${super.modifierClasses} ${mods.join(' ')}`;
  }

  toString() {
    return `<button 
					title="${this.title}"
					id="${this.id}"
					class="${this.class} ${this.modifierClasses}"
					type="${this.type}"
					${this.isDisabled ? 'disabled' : ''}
				/>`;
  }

  set onClickHandler(callback: (e: MouseEvent) => void) {
    this.setEventHandler('click', callback);
  }
}
