export interface ErrorOptions {
  breaksFlow?: boolean;
}

export class SystemError extends Error {
  private _name: string;
  private _timestamp: Date;
  private _breaksFlow: boolean;

  constructor(name: string, message: string, options?: ErrorOptions) {
    super(message);
    this._name = name;
    this._timestamp = new Date();
    this._breaksFlow = options?.breaksFlow ?? true;
  }

  static fromErrorEvent(event: ErrorEvent, options: ErrorOptions = { breaksFlow: true }) {
    const error = event.error;
    let sysError: SystemError;
    if (error?.constructor !== Error.constructor) {
      sysError = new SystemError(error?.name, error?.message, options);
    } else sysError = new SystemError(`UndefinedError`, error.message, options);

    sysError.stack = error.stack;
    return sysError;
  }

  get timestamp(): Date {
    return this._timestamp;
  }
  get name(): string {
    return this._name;
  }

  get breaksFlow(): boolean {
    return this._breaksFlow;
  }
  toString(): string {
    return `${this._name}: ${this.message} --- stack trace --- ${this.stack} `;
  }
  toJSON(): string {
    return JSON.stringify(
      {
        name: this.name,
        message: this.message,
        timestamp: this.timestamp,
        stack: this.stack,
      },
      null,
      2
    );
  }
}
