import Fuse from 'fuse.js';
import { each, filter, reduce } from 'lodash';
import { FormControl, FormControlProps } from '../../../abstracts/FormControl.abstract';
import { getIcon } from '../../media/Icon';
import { FormField } from '../../../../utils/form/FormField.class';

/** Represents an option of a ComboBox dataset */
export interface ComboBoxOptionProps {
  /** Text to be displayed */
  label: string;
  /** Actual option value */
  value: string | number | boolean;
  /** Indicates whether the option is selectable */
  disabled?: boolean;
  checked?: boolean;
}

export interface ComboBoxProps extends FormControlProps {
  /** Allows the user to select multiple options. @default false */
  allowMultiple?: boolean;
  /** Placeholder text for the input field @default "Select..." */
  placeholder?: string;
  /** If filtering is enabled, then this is used for the clear button's text @default "Clear..." */
  clearText?: string;
  /** Indicates if dataset is filterable @default false */
  allowFiltering?: boolean;
  /** Callback that receives the current dataset value each time an option is selected */
  onSelectHandler?: (selection: ComboBoxOptionProps | ComboBoxOptionProps[]) => void;
  /** Boolean flag to indicate whether the full options array should be returned, or only an array containing the checked options @default false  */
  returnFullDataset?: boolean;
  /** Dataset passed by reference. If a nullish value or an empty array is passed, the combobox is automatically disabled */
  dataset: ComboBoxOptionProps[];
  /** When provided, this will be used to filter the elements accordingly. @default fuse.js
   * @param {string} search receives the current string input from the searchbar
   * @returns {ComboBoxOptionProps[]} an array
   */
  filteringFunction?: (search: string) => ComboBoxOptionProps[];
}

export class ComboBox extends FormControl<ComboBoxOptionProps | ComboBoxOptionProps[]> {
  private _dataset: ComboBoxOptionProps[];
  private _filteredDataset: ComboBoxOptionProps[];

  private _allowMultiple: boolean;
  private _placeholder: string;
  private _onSelectHandler?: (selection: ComboBoxOptionProps | ComboBoxOptionProps[]) => void;
  private _clearText: string;
  private _isDropdownOpen: boolean;
  private _allowFiltering: boolean;
  private _filterFn: (search: string) => ComboBoxOptionProps[];
  private _returnFullDataset: boolean;

  constructor(field: FormField<ComboBoxOptionProps | ComboBoxOptionProps[]>, props: ComboBoxProps) {
    super(field, props);
    this._dataset = props?.dataset || [];
    this._filteredDataset = this._dataset;
    this._allowMultiple = props?.allowMultiple || false;
    this._placeholder = props?.placeholder || 'Select...';
    this._onSelectHandler = props?.onSelectHandler;
    this._clearText = props?.clearText || 'Clear...';
    this._isDropdownOpen = false;
    this._allowFiltering = props?.allowFiltering || false;
    this._disableOnEmptyDataset();
    this._returnFullDataset = props?.returnFullDataset ?? false;
    this._filterFn = props?.filteringFunction || this._defaultFilteringFunction;
  }

  private _createSearchBar() {
    return `<div class="${this.topClassBEM}__searchbar" >

					<input 
						class="${this.topClassBEM}__searchbar__input" 
						placeholder="${this._placeholder}"
            spellcheck="false"
            autocomplete="false"
            />

					<span class="${this.topClassBEM}__searchbar__icon">
          ${getIcon(this._isDropdownOpen ? 'arrow-up-s-line' : 'arrow-down-s-line')}
          </span>
				</div>`;
  }
  private _createDropdown() {
    return `<div 
					class="${this.topClassBEM}__dropdown"
					style="display:none"
				>
					<div class="${this.topClassBEM}__dropdown__list">
						${this._createOptionsList()}
						
					</div>
					${
            this._allowMultiple
              ? `
							<button class="${this.topClassBEM}__clear-btn">${this._clearText}</button>
							`
              : ''
          }

				</div>`;
  }
  private _refreshDropdownList() {
    this.instance?.find(`.${this.topClassBEM}__dropdown__list`).html(this._createOptionsList());
    this._onChangeEventListeners();
  }
  private _disableOnEmptyDataset() {
    if (!this._dataset || this._dataset.length === 0) this._isDisabled = true;
    else this._isDisabled = false;
  }
  private _refreshChevron() {
    this.instance
      ?.find(`.${this.topClassBEM}__searchbar__icon`)
      .html(getIcon(this._isDropdownOpen ? 'arrow-up-s-line' : 'arrow-down-s-line'));
  }

  private _createOption(props: ComboBoxOptionProps) {
    return `<label
					class='
					${this.topClassBEM}__option
					${props.disabled ? `${this.topClassBEM}__option--disabled` : ''}
          ${props.checked ? `${this.topClassBEM}__option--selected` : ''}
					'
					title="${props.label}"
					data-value="${props.value}"
          ${props.disabled ? 'data-disabled' : ''}
          tabindex="0"
				>
					<span>${props.label}</span>
          ${getIcon('check-line')}
				</label>`;
  }

  private _createOptionsList() {
    return reduce(
      this._filteredDataset,
      (acc, option) => {
        if (acc === '') {
          return this._createOption(option);
        } else {
          return acc + this._createOption(option);
        }
      },
      ''
    );
  }

  get modifierClasses(): string {
    const mods = [super.modifierClasses];
    if (this._allowFiltering) mods.push(`${this.topClassBEM}--filterable`);
    return mods.join(' ');
  }

  toString() {
    return `
			<div 
			id="${this.id}"
			class="${this.class} ${this.modifierClasses}"
			tabindex='-1'
			>
			${this._createSearchBar()}
			${this._createDropdown()}
			</div>
		`;
  }

  //=================================================== EVENT LISTENERS
  //============================== SELECTION & onCHANGE
  private _displaySelection() {
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar__input`);

    const displayLabel = reduce(
      this._dataset,
      (acc, opt) => {
        if (!opt.checked) return acc;

        if (acc === '') return opt.label;
        else return `${acc}, ${opt.label}`;
      },
      ''
    );
    input?.val(displayLabel);
    input?.attr('title', displayLabel);
  }
  private _onResetFilteredDataSearch() {
    this._displaySelection();
    this._filteredDataset = this._dataset;
    this._refreshDropdownList();
  }

  protected _onSelectHandlerProxy() {
    const data = filter(this._dataset, (e) => e.checked) as ComboBoxOptionProps[];

    if (this._allowMultiple) this._value.value = data;
    else this._value.value = data[0];

    this._onSelectHandler?.(this._returnFullDataset ? this._dataset : this._value.value);
  }

  private _singleSelectEventHandlers() {
    this.instance?.find(`.${this.topClassBEM}__option`).each((_, element) => {
      $(element).on('click', () => {
        each(this._dataset, (o) => {
          if ($(element).attr('title') === o.label) {
            o.checked = true;
          } else {
            o.checked = false;
          }
        });
        this._onResetFilteredDataSearch();
        this._onSelectHandlerProxy();
      });
    });
  }
  private _multiSelectEventHandlers() {
    this.instance?.find(`.${this.topClassBEM}__option`).each((_, element) => {
      $(element).on('click', () => {
        const targetIndex = this._dataset.findIndex((e) => e.label === $(element).attr('title'));
        this._dataset[targetIndex].checked = !this._dataset[targetIndex].checked;
        //toggle class on option
        if (this._dataset[targetIndex].checked)
          $(element).addClass(`${this.topClassBEM}__option--selected`);
        else $(element).removeClass(`${this.topClassBEM}__option--selected`);

        this._onResetFilteredDataSearch();
        this._onSelectHandlerProxy();
      });
    });
  }
  private _onChangeEventListeners() {
    //handle internal change
    if (this._allowMultiple) {
      this._multiSelectEventHandlers();
    } else {
      this._singleSelectEventHandlers();
    }
  }

  clearSelection() {
    this._dataset.forEach((e) => (e.checked = false));
    this._onResetFilteredDataSearch()
    this._onSelectHandlerProxy()
    const input = this.instance?.find('input');
    input?.val('');
    input?.removeAttr('title');
    input?.trigger('change');
  }
  private _onClearSelectionEventListeners() {
    this.instance?.find(`.${this.topClassBEM}__clear-btn`).on('click', () => this.clearSelection());
  }
  //============================== DROPDOWN CONTROL
  private _openDropdown() {
    this.instance?.addClass(`${this.topClassBEM}--topmost`);
    this.instance?.find(`.${this.topClassBEM}__dropdown`).slideDown();

    this._isDropdownOpen = true;
    this._refreshChevron();
  }

  private _closeDropdown() {
    const duration = 300;
    this.instance?.find(`.${this.topClassBEM}__dropdown`).slideUp({ duration });
    this.instance?.find(`.${this.topClassBEM}__dropdown`).scrollTop(0);
    setTimeout(() => this.instance?.removeClass(`${this.topClassBEM}--topmost`), duration);

    this._isDropdownOpen = false;
    this._refreshChevron();
  }

  private _openDropDownEventListener() {
    this.instance?.find(`.${this.topClassBEM}__searchbar`)?.on('click', () => {
      if (!this._isDropdownOpen) this._openDropdown();
      clearTimeout(this.instance?.data('blurTimeout'));
    });
  }
  private _closeDropdownOnBlur() {
    this.instance?.on('focusout', () => {
      const timeout = setTimeout(() => {
        const active = document.activeElement;
        if (!this.instance?.[0].contains(active)) {
          this._closeDropdown();
          this._onResetFilteredDataSearch();
        }
      }, 0);
      this.instance?.data('blurTimeout', timeout);
    });
  }

  private _closeDropdownOnOptionSelect() {
    this.instance
      ?.find(`.${this.topClassBEM}__dropdown__list`)
      .on('click', () => this._closeDropdown());
  }
  private _closeDropdownOnClearBtn() {
    this.instance?.find(`.${this.topClassBEM}__clear-btn`).on('click', () => this._closeDropdown());
  }
  private _dropdownControlEventListeners() {
    this._openDropDownEventListener();

    this._closeDropdownOnBlur();
    if (!this._allowMultiple) this._closeDropdownOnOptionSelect();
    else this._closeDropdownOnClearBtn();
  }
  //============================== TYPING - Filtering & Create Option
  private _defaultFilteringFunction(search: string) {
    const fuse = new Fuse(this._dataset, {
      minMatchCharLength: 2,
      includeScore: true,
      keys: ['label'],
    });
    return fuse.search(search).map((e) => e.item);
  }
  private _onSearchEventListeners() {
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar input`);

    input?.on('keyup', (e) => {
      const event = e.originalEvent;

      if (!event?.key.match(/^[\w\d\s]{1}$/) && event?.key !== 'Backspace' && event?.key !== 'Delete') return;
      const value = input.val()?.toString() || '';

      this._filteredDataset = this._filterFn(value);

      if (this._filteredDataset.length === 0) {
        this._filteredDataset = this._dataset;
      }
      this._refreshDropdownList();
    });
  }
  private _handleInputTyping() {
    const input = this.instance?.find(`.${this.topClassBEM}__searchbar input`);

    input?.on('focus', () => input.val(''));
  }

  set filteringFunction(callback: (search: string) => ComboBoxOptionProps[]) {
    this._filterFn = callback;
  }

  //==============================
  protected _applyEventListeners() {
    super._applyEventListeners();
    this._onChangeEventListeners();
    this._onClearSelectionEventListeners();
    this._dropdownControlEventListeners();
    if (this._allowFiltering) {
      this._onSearchEventListeners();
      this._handleInputTyping();
    }
  }

  //=================================================== GETTERS & SETTERS
  get dataset(): ComboBoxOptionProps[] {
    return this._dataset;
  }
  set dataset(arr: ComboBoxOptionProps[]) {
    this._dataset = arr;
    this._filteredDataset = this._dataset;
    this._disableOnEmptyDataset();
    this.render();
  }

  render() {
    super.render(false);
    this._displaySelection();
  }
}
