import { SystemError } from '../../../error-handling/errors/SystemError';
import { REMIXICON_CORE } from './remixicon.icons';

export function getIcon(iconName: keyof typeof REMIXICON_CORE) {
  if (!(iconName in REMIXICON_CORE))
    throw new SystemError('Unrecognized', `Unable to find the icon: ${iconName}.`);
  else return REMIXICON_CORE[iconName];
}
