import { forEach } from 'lodash';
import { Fragment, FragmentProps } from './Fragment';
import { View } from './View';
export interface ViewSwitcherProps<K extends string> extends FragmentProps {
  containerSelector?: string;
  selectedViewName?: K;
  onRefreshHandler?: (viewName: K, viewIndex: number, view: View) => void;
}

/**
 * A ViewSwitcher is mean to control a set of views, like a sub router.
 * Handles content change and can be used for carousels or forms with multiple screens
 */
export class ViewSwitcher<K extends string> extends Fragment {
  private _currentChild: View;
  private _currentViewName: K;
  protected _viewKeys: Record<K, number>;
  protected _children: View[];
  protected _onRefreshHandler: (viewName: K, viewIndex: number, view: View) => void;
  constructor(children?: [K, View][], props?: ViewSwitcherProps<K>) {
    super([], props);
    this._viewKeys = {} as Record<K, number>;
    this._children = [];
    this._onRefreshHandler = props?.onRefreshHandler ?? (() => {});

    forEach(children, ([key, child], index) => {
      this._children.push(child);
      this._viewKeys[key] = index;
    });

    this._currentViewName = props?.selectedViewName || (children?.[0]?.[0] as K);
    this._currentChild = this._children[this._viewKeys[this._currentViewName]];
  }

  get [Symbol.toStringTag]() {
    return 'View Switcher';
  }

  protected _renderChild(child: View): void {
    if (!(child instanceof View)) return;
    if (this._containerSelector) child.containerSelector = this._containerSelector;
    child.render(false);
  }

  render(): void {
    super.render();
    if (this?.currentChild) this.currentChild?.show();
  }

  addViews(...views: [K, View][]) {
    forEach(views, ([key, view]) => {
      this._children = [...this._children, view];
      this._viewKeys[key] = this._children.length - 1;
    });

    if (!this.currentChild) {
      this._currentViewName = views?.[0]?.[0] as K;
      this._currentChild = this._children[this._viewKeys[this._currentViewName]];
    }
  }

  setView(viewName: K) {
    this._currentChild?.hide(400, () => {
      this._currentViewName = viewName;
      this._currentChild = this._children[this._viewKeys[viewName]];
      this._currentChild.show();
      this._onRefreshHandler(viewName, this._viewKeys[viewName], this._currentChild);
    });
  }

  setViewByIndex(n: number) {
    const entry = Object.entries(this._viewKeys).find(([_, i]) => i === n);
    if (!entry) {
      throw new Error('View index is out of bounds');
    } else this.setView(entry[0] as K);
  }

  next = () => {
    const newIndex =
      this.currentViewIndex + 1 === this._children.length ? 0 : this.currentViewIndex + 1;
    this.setViewByIndex(newIndex);
  };

  previous = () => {
    const newIndex =
      this.currentViewIndex === 0 ? this._children.length - 1 : this.currentViewIndex - 1;
    this.setViewByIndex(newIndex);
  };

  get currentChild() {
    return this._currentChild;
  }

  get currentViewName() {
    return this._currentViewName;
  }

  get currentViewIndex(): number {
    return this._viewKeys[this._currentViewName];
  }
}
