import { forEach } from 'lodash';
import { HTMDNode } from '../../types/DOM/HTMDNode.type';
import UUID from '../../types/misc/UUID.type';
import { generateRuntimeUID, SPARC_PREFIX } from '../../utils/misc/identity';
import { HTMDElementInterface, isHTMDComponent } from './HTMDElementInterface.interface';

export interface HTMDElementProps {
  /** if a value is provided, sparc will not use automatic UUID generation! */
  id?: UUID;
  /** Regular HTML class names */
  class?: string;
  /** Valid CSS selector targeting the current element's parent.
   * @example
   *
   * const myElement = new Element({...,containerSelector:"#login-form",...})
   * myElement.render() //my element will be appended to #login-form
   */
  containerSelector?: string;
}

export interface ChildrenOptions {
  childrenContainerSelector?: string;
}                                

/**
 * Abstract base class for rendering structured HTML elements with
 * unique IDs, BEM-based class names, event management, and child support.
 */
export abstract class HTMDElement implements HTMDElementInterface {
  isHTMD: true;
  private _id: UUID;
  private _class: string;
  /** Contains the lowercase class name. Used in to generate default class names and to classify the element type*/
  private _name: string;
  /**
   * string|undefined
   * ---
   * should be ...but for the sake of simplicity, when undefined ill assign an empty string
   * Pardon me for the incoherence and read the HTMDElementInterface docs on the same property
   */
  protected _containerSelector: string;
  protected _children?: HTMDNode;

  constructor(children?: HTMDNode, props: HTMDElementProps = {}) {
    this._id = props?.id || generateRuntimeUID(`${SPARC_PREFIX}-element`);
    this._name = new.target.name.toLowerCase();
    this._class = '';
    this.class = props?.class || '';
    this._containerSelector = props?.containerSelector || '';
    this._children = children;
    this.isHTMD = true;
  }

  get [Symbol.toStringTag]() {
    return this._name;
  }

  private _eventsMap: {
    [K in keyof HTMLElementEventMap]?: (ev: HTMLElementEventMap[K]) => void;
  } = {};

  /**
   * Registers an event handler for a given event type on this element.
   * Replaces any previously assigned handler for the same event.
   * @param eventName The DOM event type to listen for (e.g., 'click').
   * @param callback The event handler function.
   */
  setEventHandler<K extends keyof HTMLElementEventMap>(
    eventName: K,
    callback?: (ev: HTMLElementEventMap[K]) => void
  ) {
    if (!callback) return;
    this._eventsMap[eventName] = callback as (typeof this._eventsMap)[typeof eventName];
    this.instance?.off(eventName);
    this.instance?.on(eventName, (e) => callback(e.originalEvent as HTMLElementEventMap[K]));
  }

  /**
   * Applies all stored event handlers to the DOM instance.
   */
  protected _applyEventListeners() {
    for (const [event, callback] of Object.entries(this._eventsMap) as [
      keyof HTMLElementEventMap,
      (ev: Event) => void,
    ][]) {
      if (callback) {
        this.instance?.off(event);
        this.instance?.on(event, (e) => {
          const nativeEvent = (e as JQuery.TriggeredEvent).originalEvent;
          if (nativeEvent) {
            callback(nativeEvent);
          }
        });
      }
    }
  }

  /**
   * Removes specified event handlers, or all if none are specified.
   * @param eventsList An array of event types to clear (or a single type).
   */
  clearEventListenersRecord<K extends keyof HTMLElementEventMap>(eventsList?: K | K[]) {
    const list = eventsList ? eventsList : (Object.keys(this._eventsMap) as K[]);
    for (const event of list) {
      delete this._eventsMap[event as K];
      this.instance?.off(event);
    }
  }

  clearAllEventListenersAndRecords() {
    this._eventsMap = {};
    this.removeAllEventListeners();
  }

  removeEventListeners<K extends keyof HTMLElementEventMap>(eventsList?: K | K[]) {
    const list = eventsList ? eventsList : (Object.keys(this._eventsMap) as K[]);
    for (const event of list) {
      this.instance?.off(event);
    }
  }

  removeAllEventListeners() {
    this.instance?.find('*').addBack().off();
  }

  /**
   * @returns the HTML string representing this element.
   */
  abstract toString(): string;

  private _removeChild(child: HTMDNode | undefined) {
    if (isHTMDComponent(child)) {
      (child as HTMDElementInterface).remove();
    }
    //ignore other types
    else if (typeof child === `function`) {
      this._removeChild(child());
    }
  }

  protected _removeChildren(children?: HTMDNode) {
    if (Array.isArray(children)) {
      forEach(children, (child) => this._removeChildren(child));
    } else {
      this._removeChild(children);
    }
  }
  /**
   * Removes this element from the DOM.
   */
  remove() {
    if (this.class.includes('trace-lifecycle'))
      console.trace(`REMOVING ${this._name} with id ${this._id}`);
    if (!this.isAlive) return;
    this.removeAllEventListeners();
    this._removeChildren(this._children);
    this.instance?.remove();
  }

  /**
   * Appends the element to the DOM using the configured container selector.
   * @param shouldRenderChildren Whether to render child nodes.
   */
  render(shouldRenderChildren = true, childrenOptions?: ChildrenOptions) {
    if (this.class.includes('trace-lifecycle'))
      console.trace(`RENDERING ${this._name} with id ${this._id}`);
    
    if (this.isAlive) {
      this._refresh(shouldRenderChildren, childrenOptions);
      return;
    }

    $(this._containerSelector).append(this.toString());

    this._applyEventListeners();
    if (shouldRenderChildren) this._renderChildren(this._children, childrenOptions);
  }

  /**
   * Replaces the DOM instance of this element with a re-rendered version.
   * @param shouldRenderChildren Whether to render child nodes.
   */
  private _refresh(shouldRenderChildren = true, childrenOptions?: ChildrenOptions) {
    this.instance?.replaceWith(this.toString());
    this.removeEventListeners();
    this._applyEventListeners();
    if (shouldRenderChildren) this._renderChildren(this._children, childrenOptions);
  }

  private _renderChild(child: HTMDNode, options?: ChildrenOptions) {
    if (isHTMDComponent(child)) {
      (child as HTMDElementInterface).containerSelector =
        `${this.selector} ${options?.childrenContainerSelector ?? ''}`;
      (child as HTMDElementInterface).render();
    } else if (typeof child === `function`) {
      this._renderChild(child());
      return;
    } else {
      if (options?.childrenContainerSelector) {
        this.instance?.find(options?.childrenContainerSelector)?.append(child as string);
      } else {
        this.instance?.append(child as string);
      }
    }
  }

  /**
   * Handles child rendering, removing existing nodes from the DOM, and rendering them inside this element.
   * @param childContainerSelector Leave undefined to target the root of this element. Otherwise pass a valid child selector.
   * @example
   * const childContainerSelector = undefined // this.children -> rendered directly on this.instance
   * const childContainerSelector = ".child-wrapper" // this.children -> rendered on this.instance.find(".child-wrapper")
   */
  protected _renderChildren(children = this._children, options?: ChildrenOptions) {
    if (!children) return;
    else if (Array.isArray(children)) {
      forEach(children, (child) => child && this._renderChildren(child, options));
    } else {
      this._renderChild(children, options);
    }
  }

  /**
   * Returns the jQuery DOM instance, if it is present in the DOM.
   */
  public get instance(): JQuery<HTMLElement> | null {
    return this.isAlive ? $(this.selector) : null;
  }

  /**
   * Returns the element's CSS selector.
   * @example
   * `${this._containerSelector} #${this.id}.${this.topClassBEM}`;
   */
  public get selector(): string {
    return `${this._containerSelector ?? ''} #${this.id}.${this.topClassBEM}`;
  }

  /**
   * Returns true if the element currently exists in the DOM.
   */
  public get isAlive() {
    return $(this.selector).length === 1;
  }

  /**
   * Returns the top-level BEM-style class for this element.
   */
  public get topClassBEM() {
    return `${SPARC_PREFIX}__${this.name}`;
  }
  /**
   * By default an UUID is used. Can be overridden.
   * This id can be used to identify both the object, and the DOM representation.
   */
  public get id(): UUID {
    return this._id;
  }
  /**
   * A string containing all css classes attached to the element. Note that classes added via other
   * methods will not be present here. Internally FormControls use modifierClasses, but external
   * tools can also be used to add remove classes to the DOM. This is NOT the intended use.
   *
   * Setter method ensures that element classes are not removed
   * @example
   * MyElement.class ="special-class"
   * console.log(MyElement.class) //`${SPARC_PREFIX}__${this.name} special-class`
   */
  public set class(classList: string) {
    this._class = `${SPARC_PREFIX}__${this.name}${classList ? ` ${classList}` : ''}`;
  }

  public get class(): string {
    return this._class;
  }
  /**
   * Returns the lowercase class name responsible for creating this object.
   * This property is used to define the element's main class too
   */
  public get name(): string {
    return this._name;
  }
  public set containerSelector(selector: string) {
    if (this.containerSelector === selector) return;
    this.remove();
    this._containerSelector = selector;
  }
  public get containerSelector() {
    return this._containerSelector;
  }
  /**
   * An HTMDNode to be rendered on the DOM
   * When setting the property, If the element is loaded in the DOM, it's automatically refreshed
   */
  public set children(children: HTMDNode) {
    this._children = children;
    this._refresh();
  }
  /**
   * An HTMDNode to be rendered on the DOM
   * When setting the property, If the element is loaded in the DOM, it's automatically refreshed
   */
  public get children(): HTMDNode | undefined {
    return this._children;
  }
}
