import { FormField } from '../../../../utils/form/FormField.class';
import { FormControl, FormControlProps } from '../../../abstracts/FormControl.abstract';

export interface TextInputProps extends FormControlProps {
  spellcheck?: boolean;
  autocomplete?: boolean;
  hideChars?: boolean;
  placeholder?: string;
}

export class TextInput extends FormControl<string> {
  public spellcheck: boolean;
  public autocomplete: boolean;
  public hideChars: boolean;
  public placeholder: string;
  constructor(fieldOrValue: string | FormField<string>, props: TextInputProps) {
    super(fieldOrValue, props);
    this.spellcheck = props?.spellcheck ?? false;
    this.autocomplete = props?.autocomplete ?? false;
    this.hideChars = props?.hideChars ?? false; // FIX: dates and number inputs do not use this ATM
    this.placeholder = props?.placeholder ?? '';
  }

  protected _applyEventListeners(): void {
    super._applyEventListeners();

    this.setEventHandler('blur', () => {
      this._value.value = this.instance?.val() as string;
      this._validate();
    });
  }
  toString() {
    return `<input 
                    title="${this.value}"
                    id="${this.id}"
                    class="${this.class} ${super.modifierClasses} "
                    type="${this.hideChars ? 'password' : 'text'}"
                    tabindex=0
                    spellcheck="${this.spellcheck}"
                    autocomplete="${this.autocomplete ? 'on' : 'off'}"
                    ${this.isDisabled ? 'disabled' : ''}
                    ${this.placeholder ? `placeholder=${this.placeholder}` : ''}
                    value='${this.value}'
                    />`;
  }
}
