import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { getIcon } from '../media/Icon';
import { Text } from '../typography/Text';
import { Card } from '../container/Card';
import { Modal, ModalProps } from '../container/Modal';

export type DialogVariants = 'info' | 'warning' | 'error';

export interface DialogProps extends ModalProps {
  title: string;
  content: HTMDNode;
  footer: HTMDNode;
  variant: DialogVariants;
}

export class Dialog extends Modal {
  protected _variant: DialogVariants;
  constructor(props: DialogProps) {
    const defaults = { ...props } as DialogProps;
    defaults.backdrop = props?.backdrop ?? true;
    defaults.closeOnFocusLoss = props?.closeOnFocusLoss ?? false;

    const getIconFromVariant = () => {
      switch (props.variant) {
        case 'error':
          return getIcon('error-warning-line');
        default:
          return '';
      }
    };

    super([], defaults);
    this._variant = props?.variant || `info`;
    this.children = [
      new Card([getIconFromVariant(), new Text(props?.title, { type: 'h2' })], {
        variant: 'secondary',
        class: `${this.topClassBEM}__header`,
      }),
      new Card(props.content, { variant: 'secondary', class: `${this.topClassBEM}__content` }),
      new Card(props.footer, { variant: 'secondary', class: `${this.topClassBEM}__footer` }),
    ];
  }
}
