import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { ChildrenOptions } from '../../abstracts/HTMDElement.abstract';
import { Container, ContainerProps } from './Container';
import { View } from './View';
import { ViewSwitcher } from './ViewSwitcher';

export interface TabGroupProps<K extends string> extends Omit<ContainerProps, 'selectableItems'> {
  selectedTabKey?: K;
  onTabChangeHandler?: (tabConfig: TabConfig<K>) => void;
}

export interface TabConfig<K extends string> {
  /** Unique key for the tab */
  key: K;
  /** Label displayed in the tab button */
  label: string;
  /** Content view for this tab */
  view: View;
  /** Whether this tab is disabled */
  disabled?: boolean;
}

/**
 * TabGroup component that combines tab navigation with view switching.
 * Uses ViewSwitcher internally to manage view transitions.
 */
export class TabGroup<K extends string> extends Container {
  private _viewSwitcher: ViewSwitcher<K>;
  private _tabs: TabConfig<K>[];
  private _onTabChangeHandler: (tabConfig: TabConfig<K>) => void;

  constructor(tabs: TabConfig<K>[], props: TabGroupProps<K> = {}) {
    super([], props);
    this._tabs = tabs;
    this._onTabChangeHandler = props?.onTabChangeHandler ?? (() => ({}));

    // Create ViewSwitcher with the views from tabs
    const viewEntries: [K, View][] = tabs.map((tab) => [tab.key, tab.view]);
    this._viewSwitcher = new ViewSwitcher<K>(viewEntries, {
      selectedViewName: props?.selectedTabKey,
      onRefreshHandler: (key, index, view) =>
        this._onTabChangeHandler({
          view,
          key,
          label: tabs[index].label,
          disabled: tabs[index].disabled,
        }),
    });

    this.children = [this._viewSwitcher];
  }

  get [Symbol.toStringTag]() {
    return 'Tab Group';
  }

  private _createTabButton(tab: TabConfig<K>, index: number): string {
    const isActive = this._viewSwitcher.currentViewName === tab.key;
    const disabledClass = tab.disabled ? `${this.topClassBEM}__nav__tab-btn--disabled` : '';
    const activeClass = isActive ? `${this.topClassBEM}__nav__tab-btn--active` : '';

    return `
      <button
        class="${this.topClassBEM}__nav__tab-btn ${activeClass} ${disabledClass}"
        data-tab-key="${tab.key}"
        data-tab-index="${index}"
        ${tab.disabled ? 'disabled' : ''}
        role="tab"
        aria-selected="${isActive}"
        tabindex="${isActive ? '0' : '-1'}"
      >
        ${tab.label}
      </button>
    `;
  }

  private _createTabNavigation(): string {
    const tabButtons = this._tabs.map((tab, index) => this._createTabButton(tab, index)).join('');

    return `
      <div class="${this.topClassBEM}__nav" role="tablist">
        ${tabButtons}
      </div>
    `;
  }

  toString(): string {
    return `
      <div
        id="${this.id}"
        class="${this.class}"
      >
        ${this._createTabNavigation()}
        <div class="${this.topClassBEM}__content"></div>
      </div>
    `;
  }

  render(): void {
    super.render(true, {
      childrenContainerSelector: `.${this.topClassBEM}__content`,
    });
    // this._viewSwitcher.render();
  }

  private _updateActiveTab(newKey: K): void {
    // Remove active class from all tabs
    this.instance?.find(`.${this.topClassBEM}__nav__tab-btn`).each((_, tab) => {
      $(tab).removeClass(`${this.topClassBEM}__nav__tab-btn--active`);
      $(tab).attr('aria-selected', 'false');
      $(tab).attr('tabindex', '-1');
    });

    // Add active class to selected tab
    const activeTab = this.instance?.find(`[data-tab-key="${newKey}"]`);
    activeTab?.addClass(`${this.topClassBEM}__nav__tab-btn--active`);
    activeTab?.attr('aria-selected', 'true');
    activeTab?.attr('tabindex', '0');
  }

  private _onTabClickListeners(): void {
    this.instance?.find(`.${this.topClassBEM}__nav__tab-btn`).each((_, tab) => {
      const tabKey = $(tab).attr('data-tab-key') as K;

      $(tab).on('click', () => {
        if ($(tab).attr('disabled') !== undefined) return;
        this.setTab(tabKey);
      });
    });
  }

  protected _applyEventListeners(): void {
    super._applyEventListeners();
    this._onTabClickListeners();
  }

  /**
   * Switch to a specific tab by key
   */
  setTab(tabKey: K): void {
    this._viewSwitcher.setView(tabKey);
    this._updateActiveTab(tabKey);
  }

  /**
   * Switch to a specific tab by index
   */
  setTabByIndex(index: number): void {
    this._viewSwitcher.setViewByIndex(index);
    this._updateActiveTab(this._viewSwitcher.currentViewName);
  }

  /**
   * Navigate to the next tab (wraps around)
   */
  nextTab(): void {
    this._viewSwitcher.next();
    this._updateActiveTab(this._viewSwitcher.currentViewName);
  }

  /**
   * Navigate to the previous tab (wraps around)
   */
  previousTab(): void {
    this._viewSwitcher.previous();
    this._updateActiveTab(this._viewSwitcher.currentViewName);
  }

  /**
   * Add new tabs dynamically
   */
  addTabs(...tabs: TabConfig<K>[]): void {
    this._tabs = [...this._tabs, ...tabs];
    const viewEntries: [K, View][] = tabs.map((tab) => [tab.key, tab.view]);
    this._viewSwitcher.addViews(...viewEntries);
  }

  /**
   * Get the currently active tab key
   */
  get currentTab(): K {
    return this._viewSwitcher.currentViewName;
  }

  /**
   * Get the currently active tab index
   */
  get currentTabIndex(): number {
    return this._viewSwitcher.currentViewIndex;
  }

  /**
   * Get the current view
   */
  get currentView(): View {
    return this._viewSwitcher.currentChild;
  }
}
