import { HTMDNode } from '../../../types/DOM/HTMDNode.type';
import { HTMDElement, HTMDElementProps } from '../../abstracts/HTMDElement.abstract';

export interface ViewProps extends HTMDElementProps {
  onRefreshHandler?: () => void;
  showOnRender?: boolean;
}

export class View extends HTMDElement {
  protected _onRefresh: (() => void) | (() => Promise<void>);
  public showOnRender: boolean;

  constructor(children: HTMDNode, props: ViewProps) {
    super(children, props);
    this._onRefresh = props?.onRefreshHandler ?? (() => {});
    this.showOnRender = props?.showOnRender ?? true;
  }

  toString() {
    return `<section
                    style="display:none;" 
                    id="${this.id}"
                    class="${this.class}"
                          tabindex='-1'
                />`;
  }
  /**
   * @param show Boolean flag that indicates if the page should be displayed after rendering.
   * @returns
   */
  render(show = this.showOnRender): void {
    super.render();
    if (show) this.show();
  }

  hide(duration = 400, onCompleteCallback?: () => void): void {
    this.instance?.fadeOut(duration, () => {
      onCompleteCallback?.();
      this.removeEventListeners();
    });
  }

  async show(duration = 400, onCompleteCallback?: () => void) {
    await this._onRefresh();
    this.instance?.fadeIn(duration, () => {
      onCompleteCallback?.();
    });
  }

  toggleVisibility(duration = 400, onCompleteCallback?: () => void) {
    this[this.isVisible ? 'hide' : 'show'](duration, () => onCompleteCallback?.());
  }

  get isVisible() {
    return this.instance?.is(':visible');
  }
  set children(children: HTMDNode) {
    let wasActive = this.isVisible;
    super.children = children;
    if (wasActive) {
      this.instance?.css('display', '');
      this._onRefresh();
    }
  }
  get children(): HTMDNode | undefined {
    return super.children;
  }
}
