import { cloneDeep } from 'lodash';
import { FormField, FormFieldType } from './FormField.class';

export class FormSchema<T extends Record<string, FormField<FormFieldType>>, K extends keyof T> {
  private _fields: T;
  constructor(fields: T) {
    this._fields = cloneDeep(fields);
  }

  static fromKeys<const K extends readonly string[]>(
    fieldNames: K
  ): FormSchema<{ [P in K[number]]: FormField<FormFieldType> }, K[number]> {
    const fields = Object.fromEntries(fieldNames.map((name) => [name, new FormField()])) as {
      [P in K[number]]: FormField<FormFieldType>;
    };
    return new FormSchema(fields);
  }

  get isValid() {
    return Object.values(this._fields).every((e) => e.isValid);
  }
  get hasUntouchedFields() {
    return Object.values(this._fields).some((e) => !e.wasTouched);
  }

  focusOnFirstInvalid() {
    Object.values(this._fields)
      .find((e) => !e.isValid)
      ?.focusOnInput();
  }

  get(key: K) {
    return this._fields[key];
  }

  parse() {
    const obj: Record<string, FormFieldType> = {};
    for (const key in this._fields) {
      obj[key] = this._fields[key].value;
    }
    return obj;
  }
}
