import { Dialog } from './Dialog';
import { Button } from '../form/button/Button';
import { Text } from '../typography/Text';
import { CurrentUser } from '../../../sharepoint/user/CurrentUser.abstract';
import { copyToClipboard } from '../../../utils/misc/user-actions';
import { SystemError } from '../../../error-handling/errors/SystemError';

export class BreakingErrorDialog {
  private _dialog: Dialog;
  constructor(error: SystemError) {
    this._dialog = new Dialog({
      variant: 'error',
      title: error.name,
      class: 'error-dialog',
      content: [
        new Text(error.message),
        new Text(error.stack, { class: 'error-dialog__stack-trace' }),
        new Text(
          'If this error persists, please copy the error message and send it to the support team.'
        ),
      ],
      footer: [
        new Button('Copy Error', {
          onClickHandler: () => {
            console.log('=== THE FOLLOWING WAS COPIED TO CLIPBOARD ===');
            console.log(error.toJSON());
            copyToClipboard(this._generateClipboardData(error));
          },
          variant: 'secondary',
        }),
        new Button('Reload Page', { onClickHandler: () => location.reload(), variant: 'danger' }),
      ],

      containerSelector: 'body',
    });
  }

  private _generateClipboardData(error: SystemError) {
    let user;
    try {
      user = new CurrentUser();
    } catch (e) {
      console.error('Failed to load user data:', (e as Error).message);
    }

    return JSON.stringify({
      error: error.toJSON(),
      user,
    });
  }

  render() {
    this._dialog.render();

    this._dialog.instance?.prependTo(`body`);
    setTimeout(() => {
      this._dialog.open();
    }, 0);
  }
}
